import sys
class Solution:
    def numIslands2(self, m: int, n: int, positions: list[list[int]]) -> list[int]:
        parent = {}
        rank = {}
        count = 0
        ans = []
        dirs = [[-1, 0], [1, 0], [0, -1], [0, 1]]

        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            rootx, rooty = find(x), find(y)
            if rootx != rooty:
                if rank[rootx] > rank[rooty]:
                    parent[rooty] = rootx
                elif rank[rootx] < rank[rooty]:
                    parent[rootx] = rooty
                else:
                    parent[rooty] = rootx
                    rank[rootx] += 1
                return True
            return False

        for r, c in positions:
            if (r, c) not in parent:
                parent[(r, c)] = (r, c)
                rank[(r, c)] = 0
                count += 1
                for dr, dc in dirs:
                    nr, nc = r + dr, c + dc
                    if (nr, nc) in parent:
                        if union((r, c), (nr, nc)):
                            count -= 1
            ans.append(count)
        return ans

