#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> numIslands2(int m, int n, vector<vector<int>>& positions) {
        vector<int> ans;
        if (positions.empty()) return ans;
        int count = 0;
        unordered_map<int, int> parent;
        unordered_map<int, int> rank;
        vector<pair<int, int>> dirs = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};

        function<int(int)> find = [&](int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        };

        function<bool(int, int)> union_ = [&](int x, int y) {
            int rootx = find(x), rooty = find(y);
            if (rootx != rooty) {
                if (rank[rootx] > rank[rooty]) {
                    parent[rooty] = rootx;
                } else if (rank[rootx] < rank[rooty]) {
                    parent[rootx] = rooty;
                } else {
                    parent[rooty] = rootx;
                    rank[rootx]++;
                }
                return true;
            }
            return false;
        };

        for (auto& pos : positions) {
            int r = pos[0], c = pos[1];
            int rc = r * n + c;
            if (parent.find(rc) == parent.end()) {
                parent[rc] = rc;
                rank[rc] = 0;
                count++;
                for (auto& dir : dirs) {
                    int nr = r + dir.first, nc = c + dir.second;
                    int nrc = nr * n + nc;
                    if (parent.find(nrc) != parent.end()) {
                        if (union_(rc, nrc)) {
                            count--;
                        }
                    }
                }
            }
            ans.push_back(count);
        }
        return ans;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int m, n, q;
    cin >> m >> n >> q;
    vector<vector<int>> positions(q, vector<int>(2));
    for (int i = 0; i < q; i++) {
        cin >> positions[i][0] >> positions[i][1];
    }
    Solution sol;
    vector<int> ans = sol.numIslands2(m, n, positions);
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : "\n");
    }
    cout << "\n";
    return 0;
}
